import{_ as a,o as s,c as o,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Errores comunes","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/06-errores-comunes.md","filePath":"full-stack/arquitectura/clean-architecture/06-errores-comunes.md","lastUpdated":1782521464000}'),r={name:"full-stack/arquitectura/clean-architecture/06-errores-comunes.md"};function t(n,e,l,c,d,u){return s(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h1><p>Clean Architecture se puede aplicar mal. Cuando ocurre, el proyecto gana carpetas pero pierde claridad.</p><h2 id="confundir-arquitectura-con-carpetas" tabindex="-1">Confundir arquitectura con carpetas <a class="header-anchor" href="#confundir-arquitectura-con-carpetas" aria-label="Permalink to &quot;Confundir arquitectura con carpetas&quot;">​</a></h2><p>Crear <code>domain</code>, <code>application</code> e <code>infrastructure</code> no basta. Si el dominio sigue dependiendo del ORM o los casos de uso siguen llenos de detalles HTTP, solo se ha cambiado el nombre de las carpetas.</p><h2 id="crear-abstracciones-inutiles" tabindex="-1">Crear abstracciones inutiles <a class="header-anchor" href="#crear-abstracciones-inutiles" aria-label="Permalink to &quot;Crear abstracciones inutiles&quot;">​</a></h2><p>No todo necesita una interfaz. Una interfaz aporta valor cuando:</p><ul><li>Hay varias implementaciones reales.</li><li>Quieres proteger un caso de uso de un detalle externo.</li><li>Necesitas tests rapidos sin infraestructura.</li><li>El proveedor puede cambiar.</li></ul><p>Si solo existe una implementacion y no hay motivo de cambio, puede esperar.</p><h2 id="anemia-de-dominio" tabindex="-1">Anemia de dominio <a class="header-anchor" href="#anemia-de-dominio" aria-label="Permalink to &quot;Anemia de dominio&quot;">​</a></h2><p>Un dominio anemico tiene entidades sin comportamiento y servicios gigantes que hacen todo.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OrderService.confirm(order)</span></span></code></pre></div><p>Puede ser mejor:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order.confirm()</span></span></code></pre></div><p>La regla vive con los datos que protege.</p><h2 id="casos-de-uso-demasiado-pequenos" tabindex="-1">Casos de uso demasiado pequenos <a class="header-anchor" href="#casos-de-uso-demasiado-pequenos" aria-label="Permalink to &quot;Casos de uso demasiado pequenos&quot;">​</a></h2><p>No todos los metodos CRUD merecen un caso de uso aislado si no expresan una intencion real.</p><p>Mal:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UpdateUserUseCase</span></span></code></pre></div><p>Mejor:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ChangeUserEmailUseCase</span></span>
<span class="line"><span>DisableUserUseCase</span></span>
<span class="line"><span>AcceptUserInvitationUseCase</span></span></code></pre></div><h2 id="filtrar-detalles-hacia-dentro" tabindex="-1">Filtrar detalles hacia dentro <a class="header-anchor" href="#filtrar-detalles-hacia-dentro" aria-label="Permalink to &quot;Filtrar detalles hacia dentro&quot;">​</a></h2><p>Ejemplos tipicos:</p><ul><li>Entidades con decoradores del ORM.</li><li>Casos de uso que reciben <code>Request</code>.</li><li>Dominio que lanza errores HTTP.</li><li>Repositorios que devuelven modelos de base de datos.</li></ul><h2 id="sobrearquitectura" tabindex="-1">Sobrearquitectura <a class="header-anchor" href="#sobrearquitectura" aria-label="Permalink to &quot;Sobrearquitectura&quot;">​</a></h2><p>No todos los proyectos necesitan Clean Architecture completa. Para un MVP, puede bastar con separar controladores, servicios y repositorios. La arquitectura debe acompanarte, no bloquearte.</p><h2 id="checklist-de-revision" tabindex="-1">Checklist de revision <a class="header-anchor" href="#checklist-de-revision" aria-label="Permalink to &quot;Checklist de revision&quot;">​</a></h2><ul><li>Puedes explicar cada capa sin hablar del framework.</li><li>Puedes probar el dominio sin infraestructura.</li><li>Puedes cambiar la base de datos tocando pocos archivos.</li><li>Los nombres reflejan negocio, no solo CRUD.</li><li>La estructura ayuda a leer el sistema.</li></ul>`,27)])])}const m=a(r,[["render",t]]);export{h as __pageData,m as default};
